   521→// Analyze speech transcription for communication quality
   522→function analyzeSpeechPatterns(transcription, durationSeconds) {
   523→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   524→  const wordCount = words.length;
   525→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   526→
   527→  // Filler word detection
   528→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   529→  const fillerCounts = {};
   530→  let totalFillers = 0;
   531→  const lowerTranscription = transcription.toLowerCase();
   532→
